import React, { useEffect, useMemo, useRef, useState } from "react";
import axios from "axios";
import "./App.css";

// Note: You'll need to install these UI components or create equivalent ones
// For now, I'm including basic implementations

const BACKEND_URL = "http://127.0.0.1:8000";
const API = `${BACKEND_URL}/api`;

// Basic UI Components (you can replace these with your preferred UI library)
const Card = ({ children, className = "" }) => (
  <div className={`border rounded-lg shadow-sm bg-white ${className}`}>
    {children}
  </div>
);

const CardHeader = ({ children }) => (
  <div className="px-6 py-4 border-b border-gray-200">
    {children}
  </div>
);

const CardTitle = ({ children, className = "" }) => (
  <h3 className={`text-lg font-semibold ${className}`}>
    {children}
  </h3>
);

const CardContent = ({ children, className = "" }) => (
  <div className={`px-6 py-4 ${className}`}>
    {children}
  </div>
);

const Input = React.forwardRef(({ className = "", ...props }, ref) => (
  <input
    ref={ref}
    className={`w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 ${className}`}
    {...props}
  />
));

const Button = ({ children, onClick, className = "", variant = "primary", size = "md", disabled = false, ...props }) => {
  const baseClasses = "font-medium rounded-md focus:outline-none focus:ring-2 focus:ring-offset-2";
  const variants = {
    primary: "bg-blue-600 text-white hover:bg-blue-700 focus:ring-blue-500",
    outline: "border border-gray-300 bg-white text-gray-700 hover:bg-gray-50 focus:ring-blue-500",
    destructive: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500"
  };
  const sizes = {
    sm: "px-2 py-1 text-sm",
    md: "px-4 py-2",
    lg: "px-6 py-3 text-lg"
  };

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`${baseClasses} ${variants[variant]} ${sizes[size]} ${disabled ? 'opacity-50 cursor-not-allowed' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

const Label = ({ children, className = "" }) => (
  <label className={`block text-sm font-medium text-gray-700 mb-1 ${className}`}>
    {children}
  </label>
);

const Table = ({ children, className = "" }) => (
  <div className="overflow-x-auto">
    <table className={`min-w-full divide-y divide-gray-200 ${className}`}>
      {children}
    </table>
  </div>
);

const TableHeader = ({ children }) => (
  <thead className="bg-gray-50">
    {children}
  </thead>
);

const TableBody = ({ children }) => (
  <tbody className="bg-white divide-y divide-gray-200">
    {children}
  </tbody>
);

const TableRow = ({ children, className = "" }) => (
  <tr className={className}>
    {children}
  </tr>
);

const TableHead = ({ children, className = "" }) => (
  <th className={`px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider ${className}`}>
    {children}
  </th>
);

const TableCell = ({ children, className = "" }) => (
  <td className={`px-6 py-4 whitespace-nowrap text-sm text-gray-900 ${className}`}>
    {children}
  </td>
);

const Tabs = ({ children, value, onValueChange }) => (
  <div>
    {React.Children.map(children, child => 
      React.cloneElement(child, { activeTab: value, onTabChange: onValueChange })
    )}
  </div>
);

const TabsList = ({ children, activeTab, onTabChange }) => (
  <div className="flex space-x-1 bg-gray-100 p-1 rounded-lg">
    {React.Children.map(children, (child, index) => 
      React.cloneElement(child, { 
        isActive: child.props.value === activeTab, 
        onClick: () => onTabChange(child.props.value) 
      })
    )}
  </div>
);

const TabsTrigger = ({ children, value, isActive, onClick, className = "" }) => (
  <button
    onClick={onClick}
    className={`px-3 py-2 text-sm font-medium rounded-md transition-colors ${
      isActive 
        ? 'bg-white text-gray-900 shadow-sm' 
        : 'text-gray-600 hover:text-gray-900 hover:bg-gray-200'
    } ${className}`}
  >
    {children}
  </button>
);

const TabsContent = ({ children, value, activeTab }) => (
  activeTab === value ? <div>{children}</div> : null
);

const Textarea = ({ className = "", ...props }) => (
  <textarea
    className={`w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 ${className}`}
    {...props}
  />
);

// Toast notification system (simple implementation)
const toast = {
  success: (message) => {
    console.log('Success:', message);
    // You can implement a proper toast notification here
    alert('✅ ' + message);
  },
  error: (message) => {
    console.error('Error:', message);
    // You can implement a proper toast notification here
    alert('❌ ' + message);
  }
};

// Icons (simple implementations)
const LockKeyhole = ({ size = 16 }) => <span style={{fontSize: size}}>🔒</span>;
const ChefHat = ({ size = 16 }) => <span style={{fontSize: size}}>👨‍🍳</span>;
const FileText = ({ size = 16 }) => <span style={{fontSize: size}}>📄</span>;
const History = ({ size = 16 }) => <span style={{fontSize: size}}>📊</span>;
const Printer = ({ size = 16 }) => <span style={{fontSize: size}}>🖨️</span>;
const Plus = ({ size = 16 }) => <span style={{fontSize: size}}>➕</span>;
const Minus = ({ size = 16 }) => <span style={{fontSize: size}}>➖</span>;
const Trash2 = ({ size = 16 }) => <span style={{fontSize: size}}>🗑️</span>;
const Save = ({ size = 16 }) => <span style={{fontSize: size}}>💾</span>;
const HelpCircle = ({ size = 16 }) => <span style={{fontSize: size}}>❓</span>;
const Loader2 = ({ size = 16, className = "" }) => (
  <span className={`inline-block animate-spin ${className}`} style={{fontSize: size}}>⏳</span>
);

function LoginPanel({ onLogin, onStartAdminVerification }) {
  const [credential, setCredential] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const [track, setTrack] = useState("");

  const handleKeyDown = (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      submit(event.shiftKey);
    }
  };

  const submit = async (isRoot = false) => {
    if (!date || !track) {
      toast.error("Please select a date and track.");
      return;
    }

    const validTracks = ["", "`", "RBS1", "RBS2"];
    if (
      !validTracks.map((t) => t.toUpperCase()).includes(track.toUpperCase())
    ) {
      toast.error(
        "Invalid track selected. Valid tracks are ' ', '`', 'RBS1', 'RBS2'."
      );
      return;
    }

    if (credential.toUpperCase() === "SHI" && isRoot) {
      onStartAdminVerification(date, track);
      return;
    }

    try {
      const res = await axios.post(`${API}/auth/login`, {
        staff_code: credential,
        is_root: isRoot,
      });
      onLogin(res.data.mode, date, track);
      toast.success(
        res.data.mode.includes("admin")
          ? `Logged in as ${res.data.mode}`
          : "Clerk mode"
      );
    } catch (e) {
      onLogin("none", null, null);
      toast.error(e?.response?.data?.detail || "Invalid login");
    }
  };

  return (
    <Card className="max-w-md mx-auto shadow-xl">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <LockKeyhole size={18} /> Staff Access
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-3">
        <div className="grid grid-cols-3 items-center gap-3">
          <Label className="text-sm">Credential</Label>
          <Input
            placeholder="Enter credential"
            className="col-span-2"
            value={credential}
            onChange={(e) => setCredential(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>
        <div className="grid grid-cols-3 items-center gap-3">
          <Label className="text-sm">Date</Label>
          <Input
            type="date"
            className="col-span-2"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>
        <div className="grid grid-cols-3 items-center gap-3">
          <Label className="text-sm">Track</Label>
          <Input
            placeholder="e.g., RBS1"
            className="col-span-2"
            value={track}
            onChange={(e) => setTrack(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>
        <div className="flex justify-end">
          <Button onClick={() => submit(false)} className="px-5">
            Enter
          </Button>
        </div>
        <div className="text-xs text-gray-500">
          <p>
            Hint: Use 'CLK' for clerk, 'SHI' for admin, or 'SHI' + Shift+Enter
            for root admin.
          </p>
        </div>
      </CardContent>
    </Card>
  );
}

function AdminVerificationScreen({ onVerificationComplete }) {
  useEffect(() => {
    const handleKeyDown = (event) => {
      if (event.altKey && event.key.toLowerCase() === "a") {
        event.preventDefault();
        onVerificationComplete("admin-full");
      }
    };

    const timer = setTimeout(() => {
      onVerificationComplete("admin-limited");
    }, 5000);

    window.addEventListener("keydown", handleKeyDown);

    return () => {
      clearTimeout(timer);
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [onVerificationComplete]);

  return (
    <div className="flex flex-col items-center justify-center min-h-[50vh]">
      <Loader2 size={48} className="text-orange-500 mb-4" />
      <p className="mt-4 text-lg text-gray-600">Verifying Admin Access...</p>
      <p className="text-sm text-gray-500">Press the key combination now</p>
    </div>
  );
}

function FoodMenu({ mode }) {
  const [items, setItems] = useState([]);
  const [newItem, setNewItem] = useState({
    name: "",
    alpha_code: "",
    numeric_code: "",
    price_fixed: "",
    price_general: "",
    price_ac: "",
  });

  const load = async () => {
    try {
      const res = await axios.get(`${API}/menu`);
      setItems(res.data);
    } catch (e) {
      toast.error("Failed to load menu");
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleNewItemChange = (e) => {
    const { name, value } = e.target;
    setNewItem((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddItem = async () => {
    try {
      await axios.post(`${API}/menu`, newItem);
      toast.success("Item added successfully");
      setNewItem({
        name: "",
        alpha_code: "",
        numeric_code: "",
        price_fixed: "",
        price_general: "",
        price_ac: "",
      });
      load();
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Failed to add item");
    }
  };

  const handleDeleteItem = async (itemId) => {
    try {
      await axios.delete(`${API}/menu/${itemId}`);
      toast.success("Item deleted successfully");
      load();
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Failed to delete item");
    }
  };

  return (
    <Card className="shadow-md">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <ChefHat size={18} /> Food Menu
        </CardTitle>
      </CardHeader>
      <CardContent>
        {mode === "admin-full" && (
          <div className="grid grid-cols-7 gap-2 mb-4 items-end">
            <Input
              name="name"
              placeholder="Name"
              value={newItem.name}
              onChange={handleNewItemChange}
            />
            <Input
              name="alpha_code"
              placeholder="Alpha"
              value={newItem.alpha_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="numeric_code"
              placeholder="Numeric"
              value={newItem.numeric_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_fixed"
              placeholder="Fixed"
              value={newItem.price_fixed}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_general"
              placeholder="General"
              value={newItem.price_general}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_ac"
              placeholder="AC"
              value={newItem.price_ac}
              onChange={handleNewItemChange}
            />
            <Button onClick={handleAddItem}>Add Item</Button>
          </div>
        )}
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Item</TableHead>
              <TableHead>Alpha</TableHead>
              <TableHead>Numeric</TableHead>
              <TableHead>Fixed</TableHead>
              <TableHead>General</TableHead>
              <TableHead>AC</TableHead>
              {mode === "admin-full" && <TableHead>Actions</TableHead>}
            </TableRow>
          </TableHeader>
          <TableBody>
            {items.map((it) => (
              <TableRow key={it.id}>
                <TableCell>{it.name}</TableCell>
                <TableCell>{it.alpha_code}</TableCell>
                <TableCell>{it.numeric_code}</TableCell>
                <TableCell>₹ {it.price_fixed}</TableCell>
                <TableCell>₹ {it.price_general}</TableCell>
                <TableCell>₹ {it.price_ac}</TableCell>
                {mode === "admin-full" && (
                  <TableCell>
                    <Button
                      variant="destructive"
                      size="sm"
                      onClick={() => handleDeleteItem(it.id)}
                    >
                      <Trash2 size={14} />
                    </Button>
                  </TableCell>
                )}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

function Billing({
  drafts,
  setDrafts,
  currentTable,
  setCurrentTable,
  billingDate,
  activeTab,
  track,
}) {
  const [entryCode, setEntryCode] = useState("");
  const [qty, setQty] = useState(1);
  const [nextBillNumber, setNextBillNumber] = useState(null);

  const tableNoRef = useRef(null);
  const itemCodeRef = useRef(null);
  const qtyRef = useRef(null);

  const [showHelp, setShowHelp] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [menuItems, setMenuItems] = useState([]);
  const [filteredItems, setFilteredItems] = useState([]);
  const [selectedHelpIndex, setSelectedHelpIndex] = useState(0);
  const searchInputRef = useRef(null);

  const currentDraft = useMemo(
    () =>
      drafts[currentTable] || {
        header: {
          table_no: currentTable,
          party_no: "1",
          section: "G",
          track: track,
        },
        lines: [],
        modified_from_bill_id: null,
      },
    [drafts, currentTable, track]
  );

  useEffect(() => {
    const loadMenu = async () => {
      try {
        const res = await axios.get(`${API}/menu`);
        setMenuItems(res.data);
        setFilteredItems(res.data);
      } catch (e) {
        toast.error("Failed to load menu for help panel");
      }
    };
    loadMenu();
  }, []);

  useEffect(() => {
    if (activeTab === "billing" && tableNoRef.current) {
      tableNoRef.current.focus();
    }
  }, [activeTab]);

  const handlePrintBill = async () => {
    if (!currentTable) {
      toast.error("Please enter a table number before printing.");
      return;
    }

    let finalLines = currentDraft.lines;

    if (document.activeElement === qtyRef.current && entryCode) {
      const newItem = await addItem(false);
      if (newItem) {
        finalLines = [...finalLines, newItem];
      } else {
        return;
      }
    }

    if (finalLines.length === 0) {
      toast.error("Please add at least one item to the bill.");
      return;
    }

    createBill(finalLines);
  };

  useEffect(() => {
    const handleGlobalKeyDown = (event) => {
      if (event.key === "End" || event.key === "Home") {
        event.preventDefault();
        handlePrintBill();
      }
    };
    window.addEventListener("keydown", handleGlobalKeyDown);
    return () => {
      window.removeEventListener("keydown", handleGlobalKeyDown);
    };
  }, [currentTable, entryCode, qty, currentDraft.lines]);

  useEffect(() => {
    if (billingDate) {
      const fetchNextBillNumber = async () => {
        try {
          const res = await axios.get(`${API}/bill/next_number`, {
            params: { bill_date: billingDate },
          });
          setNextBillNumber(res.data.bill_number);
        } catch (e) {
          toast.error("Failed to fetch next bill number.");
          setNextBillNumber(1);
        }
      };
      fetchNextBillNumber();
    }
  }, [billingDate]);

  const onHeaderChange = (patch) => {
    const newHeader = { ...currentDraft.header, ...patch };
    const newDraft = { ...currentDraft, header: newHeader };
    setDrafts((prev) => ({ ...prev, [currentTable]: newDraft }));
  };

  const setSectionByTable = (tableNo) => {
    const table = parseInt(tableNo, 10);
    if (isNaN(table)) return;

    let section = "G";
    if (table === 1) {
      section = "P";
    } else if (table >= 15 && table <= 30) {
      section = "AC";
    }
    onHeaderChange({ section });
  };

  const loadDataForTable = async (tableNo) => {
    if (!tableNo) return;

    setSectionByTable(tableNo);

    if (drafts[tableNo]) return;
    try {
      const res = await axios.get(`${API}/bill/last`, {
        params: { table_no: tableNo, bill_date: billingDate },
      });
      const lastBill = res.data;
      setDrafts((prev) => ({
        ...prev,
        [tableNo]: {
          header: lastBill.header,
          lines: lastBill.items,
          modified_from_bill_id: lastBill.id,
        },
      }));
      toast.success(`Loaded last bill for table ${tableNo}`);
    } catch (e) {
      setDrafts((prev) => ({
        ...prev,
        [tableNo]: {
          header: {
            table_no: tableNo,
            party_no: "1",
            section: "G",
            bill_number: null,
          },
          lines: [],
        },
      }));
    }
  };

  const handleTableNoKeyDown = (event) => {
    if (event.key === "PageDown") {
      itemCodeRef.current.focus();
    } else if (event.key === "Enter") {
      const newTableNo = event.target.value;
      setCurrentTable(newTableNo);
      loadDataForTable(newTableNo);
    }
  };

  const addItem = async (focusItemCode = true) => {
    if (!entryCode || !currentTable) return null;
    try {
      const res = await axios.get(`${API}/menu/lookup/${entryCode}`);
      const item = res.data;
      const unit =
        currentDraft.header.section === "AC"
          ? item.price_ac
          : item.price_general;
      const newLine = {
        code: entryCode.toUpperCase(),
        name: item.name,
        quantity: qty,
        unit_price: unit,
        line_total: +(unit * qty).toFixed(2),
      };

      if (focusItemCode) {
        const updatedLines = [...currentDraft.lines, newLine];
        setDrafts((prev) => ({
          ...prev,
          [currentTable]: { ...currentDraft, lines: updatedLines },
        }));
        setEntryCode("");
        setQty(1);
        itemCodeRef.current.focus();
      }
      return newLine;
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Item not found");
      return null;
    }
  };

  const handleItemCodeKeyDown = (e) => {
    if (e.key === "F1") {
      e.preventDefault();
      setShowHelp(true);
    } else if (e.key === "Escape") {
      e.preventDefault();
      setShowHelp(false);
      itemCodeRef.current.focus();
    } else if (e.key === "Enter" && entryCode) {
      e.preventDefault();
      const item = menuItems.find(
        (i) =>
          i.numeric_code === entryCode ||
          i.alpha_code.toLowerCase() === entryCode.toLowerCase()
      );
      if (item) {
        qtyRef.current.focus();
        qtyRef.current.select();
      } else {
        setShowHelp(true);
      }
    }
  };

  const handleQtyKeyDown = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      addItem();
    }
  };

  const updateQty = (index, newQty) => {
    if (newQty <= 0) {
      removeLine(index);
      return;
    }
    const updatedLines = currentDraft.lines.map((l, i) => {
      if (i !== index) return l;
      return {
        ...l,
        quantity: newQty,
        line_total: +(l.unit_price * newQty).toFixed(2),
      };
    });
    setDrafts((prev) => ({
      ...prev,
      [currentTable]: { ...currentDraft, lines: updatedLines },
    }));
  };

  const removeLine = (index) => {
    const updatedLines = currentDraft.lines.filter((_, i) => i !== index);
    setDrafts((prev) => ({
      ...prev,
      [currentTable]: { ...currentDraft, lines: updatedLines },
    }));
  };

  const subtotal = useMemo(
    () => currentDraft.lines.reduce((s, l) => s + l.line_total, 0),
    [currentDraft.lines]
  );
  const sgst = useMemo(() => +(subtotal * 0.025).toFixed(2), [subtotal]);
  const cgst = useMemo(() => +(subtotal * 0.025).toFixed(2), [subtotal]);
  const total = useMemo(
    () => +(subtotal + sgst + cgst),
    [subtotal, sgst, cgst]
  );

  const createBill = async (lines) => {
    const h = currentDraft.header;
    try {
      const payload = {
        header: { ...h },
        item_codes: lines.map((l) => l.code),
        quantities: lines.map((l) => l.quantity),
        bill_date: billingDate,
        modified_from_bill_id: currentDraft.modified_from_bill_id,
      };
      const res = await axios.post(`${API}/bill`, payload);
      toast.success(`Bill #${res.data.header.bill_number} created`);
      window.printBillData = res.data;

      setDrafts((prev) => {
        const newDrafts = { ...prev };
        delete newDrafts[currentTable];
        return newDrafts;
      });
      setCurrentTable("");
      setEntryCode("");
      setQty(1);

      setNextBillNumber(res.data.header.bill_number + 1);

      setTimeout(() => {
        window.print();
        tableNoRef.current.focus();
      }, 200);
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Failed to create bill");
    }
  };

  const displayBillNumber =
    currentDraft.header.bill_number != null
      ? currentDraft.header.bill_number
      : nextBillNumber;

  // Help Panel Logic
  useEffect(() => {
    if (showHelp) {
      setSearchQuery("");
      setFilteredItems(menuItems);
      setSelectedHelpIndex(0);
      setTimeout(() => searchInputRef.current?.focus(), 0);
    }
  }, [showHelp, menuItems]);

  useEffect(() => {
    const lowercasedQuery = searchQuery.toLowerCase();
    const filtered = menuItems.filter(
      (item) =>
        item.name.toLowerCase().includes(lowercasedQuery) ||
        item.numeric_code?.toLowerCase().includes(lowercasedQuery) ||
        item.alpha_code?.toLowerCase().includes(lowercasedQuery)
    );
    setFilteredItems(filtered);
    setSelectedHelpIndex(0);
  }, [searchQuery, menuItems]);

  const handleSearchKeyDown = (e) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setSelectedHelpIndex((prev) => (prev + 1) % filteredItems.length);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setSelectedHelpIndex(
        (prev) => (prev - 1 + filteredItems.length) % filteredItems.length
      );
    } else if (e.key === "Enter") {
      e.preventDefault();
      if (filteredItems[selectedHelpIndex]) {
        const selectedItem = filteredItems[selectedHelpIndex];
        setEntryCode(selectedItem.numeric_code || selectedItem.alpha_code);
        setShowHelp(false);
        qtyRef.current.focus();
        qtyRef.current.select();
      }
    } else if (e.key === "Escape") {
      e.preventDefault();
      setShowHelp(false);
      itemCodeRef.current.focus();
    }
  };

  return (
    <div className="grid grid-cols-12 gap-6 h-full">
      <div className="col-span-8">
        <Card className="h-full flex flex-col">
          <CardHeader>
            <CardTitle>Billing for {billingDate}</CardTitle>
          </CardHeader>
          <CardContent className="flex-1 flex flex-col space-y-4">
            {/* Header Info */}
            <div className="grid grid-cols-4 gap-4">
              <div>
                <Label>Table No</Label>
                <Input
                  ref={tableNoRef}
                  placeholder="Type & Enter"
                  value={currentTable}
                  onChange={(e) => setCurrentTable(e.target.value)}
                  onKeyDown={handleTableNoKeyDown}
                />
              </div>
              <div>
                <Label>Party No.</Label>
                <Input
                  value={currentDraft.header.party_no || ""}
                  onChange={(e) => onHeaderChange({ party_no: e.target.value })}
                />
              </div>
              <div>
                <Label>Section</Label>
                <Input value={currentDraft.header.section || "G"} readOnly />
              </div>
              <div>
                <Label>Bill No.</Label>
                <Input value={displayBillNumber || ""} readOnly />
              </div>
            </div>

            {/* Item Entry */}
            <div className="grid grid-cols-12 gap-4 items-end">
              <div className="col-span-5">
                <Label>Item Code (F1 for Help)</Label>
                <Input
                  ref={itemCodeRef}
                  type="text"
                  placeholder="Enter Item Code"
                  value={entryCode}
                  onChange={(e) => setEntryCode(e.target.value)}
                  onKeyDown={handleItemCodeKeyDown}
                />
              </div>
              <div className="col-span-2">
                <Label>Quantity</Label>
                <Input
                  ref={qtyRef}
                  type="number"
                  value={qty}
                  onChange={(e) => setQty(Number(e.target.value))}
                  onKeyDown={handleQtyKeyDown}
                />
              </div>
              <div className="col-span-5 flex gap-2">
                <Button
                  onClick={() => addItem()}
                  disabled={!currentTable}
                  className="w-full"
                >
                  Add Item
                </Button>
                <Button
                  variant="outline"
                  onClick={() => {
                    if (currentTable)
                      setDrafts((prev) => ({
                        ...prev,
                        [currentTable]: { ...currentDraft, lines: [] },
                      }));
                  }}
                  className="w-full"
                >
                  Clear Items
                </Button>
              </div>
            </div>

            {/* Bill Table */}
            <div className="flex-1 border rounded-md overflow-hidden">
              <div className="h-full overflow-y-auto">
                <Table>
                  <TableHeader className="sticky top-0 bg-gray-50">
                    <TableRow>
                      <TableHead className="w-12">No.</TableHead>
                      <TableHead>Item</TableHead>
                      <TableHead className="text-right w-48">Qty</TableHead>
                      <TableHead className="text-right">Rate</TableHead>
                      <TableHead className="text-right">Amount</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {currentDraft.lines.map((l, idx) => (
                      <TableRow key={idx}>
                        <TableCell>{idx + 1}</TableCell>
                        <TableCell>{l.name}</TableCell>
                        <TableCell className="text-right">
                          <div className="flex items-center justify-end gap-2">
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => updateQty(idx, l.quantity - 1)}
                            >
                              <Minus size={14} />
                            </Button>
                            <span className="w-8 text-center">
                              {l.quantity}
                            </span>
                            <Button
                              size="sm"
                              onClick={() => updateQty(idx, l.quantity + 1)}
                            >
                              <Plus size={14} />
                            </Button>
                          </div>
                        </TableCell>
                        <TableCell className="text-right">
                          ₹ {l.unit_price.toFixed(2)}
                        </TableCell>
                        <TableCell className="text-right">
                          ₹ {l.line_total.toFixed(2)}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="col-span-4 flex flex-col gap-6">
        <Card className="flex-1 flex flex-col">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <HelpCircle size={18} />
              Help
            </CardTitle>
          </CardHeader>
          <CardContent className="flex-1 flex flex-col">
            {!showHelp && (
              <div className="text-sm text-gray-600 my-auto space-y-4">
                <p className="text-center">
                  Press F1 in Item Code to search for items.
                </p>
                <div>
                  <h4 className="font-semibold mb-2 text-center">
                    Keyboard Shortcuts
                  </h4>
                  <ul className="space-y-1 list-disc list-inside text-xs">
                    <li>
                      <span className="font-semibold">F1</span>: Open item
                      search in Help Panel
                    </li>
                    <li>
                      <span className="font-semibold">Esc</span>: Close item
                      search in Help Panel
                    </li>
                    <li>
                      <span className="font-semibold">Enter</span>: Move between
                      fields / Add item
                    </li>
                    <li>
                      <span className="font-semibold">Arrow Up/Down</span>:
                      Navigate search results
                    </li>
                    <li>
                      <span className="font-semibold">PageDown</span>: Move from
                      Table No. to Item Code
                    </li>
                    <li>
                      <span className="font-semibold">End / Home</span>:
                      Finalize and Print Bill
                    </li>
                  </ul>
                </div>
              </div>
            )}
            {showHelp && (
              <div className="flex flex-col h-full">
                <Input
                  ref={searchInputRef}
                  type="text"
                  placeholder="Search by code or name..."
                  className="mb-4"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={handleSearchKeyDown}
                />
                <div className="flex-1 border rounded-md overflow-y-auto">
                  <Table>
                    <TableHeader className="sticky top-0 bg-gray-50">
                      <TableRow>
                        <TableHead>Code</TableHead>
                        <TableHead>Name</TableHead>
                        <TableHead className="text-right">Price</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {filteredItems.map((item, index) => (
                        <TableRow
                          key={item.id}
                          className={`cursor-pointer hover:bg-gray-100 ${
                            selectedHelpIndex === index ? "bg-blue-100" : ""
                          }`}
                          onClick={() => {
                            setEntryCode(item.numeric_code || item.alpha_code);
                            setShowHelp(false);
                            qtyRef.current.focus();
                            qtyRef.current.select();
                          }}
                        >
                          <TableCell>
                            {item.numeric_code || item.alpha_code}
                          </TableCell>
                          <TableCell>{item.name}</TableCell>
                          <TableCell className="text-right">
                            ₹{item.price_general.toFixed(2)}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle>Finalize Bill</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span>Subtotal:</span>
                <span>{subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>SGST (2.5%):</span>
                <span>{sgst.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>CGST (2.5%):</span>
                <span>{cgst.toFixed(2)}</span>
              </div>
              <div className="flex justify-between font-bold text-lg border-t pt-2">
                <span>Grand Total:</span>
                <span>₹{Math.round(total).toFixed(2)}</span>
              </div>
            </div>
            <Button
              size="lg"
              className="h-12 text-lg gap-2 w-full"
              onClick={handlePrintBill}
            >
              <Printer size={20} /> Print Bill
            </Button>
          </CardContent>
        </Card>
      </div>
      <div className="print-area hidden">
        <BillPrint />
      </div>
    </div>
  );
}

function RecentBills({ billingDate }) {
  const [bills, setBills] = useState([]);

  const loadRecentBills = async () => {
    try {
      const res = await axios.get(`${API}/bills/by_date`, {
        params: { bill_date: billingDate },
      });
      setBills(res.data);
    } catch (e) {
      toast.error("Failed to load recent bills.");
    }
  };

  useEffect(() => {
    if (billingDate) {
      loadRecentBills();
    }
  }, [billingDate]);

  return (
    <Card className="shadow-md">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <History size={18} /> Recent Bills for {billingDate}
        </CardTitle>
      </CardHeader>
      <CardContent>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Bill No</TableHead>
              <TableHead>Table</TableHead>
              <TableHead>Time</TableHead>
              <TableHead>Amount</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {bills.map((bill) => (
              <TableRow key={bill.id}>
                <TableCell>{bill.bill_number}</TableCell>
                <TableCell>{bill.table_no}</TableCell>
                <TableCell>
                  {new Date(bill.created_at).toLocaleTimeString()}
                </TableCell>
                <TableCell>₹ {bill.grand_total.toFixed(2)}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

function BillPrint({ billData }) {
  const data =
    billData || (typeof window !== "undefined" && window.printBillData) || null;
  if (!data) return null;

  return (
    <div className="print-receipt" style={{ fontFamily: 'monospace', fontSize: '12px', maxWidth: '300px' }}>
      <div className="text-center font-bold text-base">{data.hotel_name}</div>
      {data.address && (
        <div className="text-center text-xs">{data.address}</div>
      )}
      <div className="text-center text-xs">
        GST Included{data.gstin ? ` • GSTIN: ${data.gstin}` : ""}
        {data.phone ? ` • Ph: ${data.phone}` : ""}
      </div>
      <div className="divider">{"=".repeat(40)}</div>
      <div className="flex justify-between">
        <span>Bill No</span>
        <span>{data.header.bill_number}</span>
      </div>
      <div className="flex justify-between">
        <span>Date</span>
        <span>{new Date(data.created_at).toLocaleString()}</span>
      </div>
      <div className="flex justify-between">
        <span>Table</span>
        <span>{data.header.table_no}</span>
      </div>
      <div className="divider">{"=".repeat(40)}</div>
      <table className="w-full text-xs">
        <thead>
          <tr>
            <th className="text-left w-12">No.</th>
            <th className="text-left">Item</th>
            <th className="text-right">Qty</th>
            <th className="text-right">Rate</th>
            <th className="text-right">Amt</th>
          </tr>
        </thead>
        <tbody>
          {data.items.map((it, i) => (
            <tr key={i}>
              <td>{i + 1}</td>
              <td>{it.name}</td>
              <td className="text-right">{it.quantity}</td>
              <td className="text-right">{it.unit_price.toFixed(2)}</td>
              <td className="text-right">{it.line_total.toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
      </table>
      <div className="divider">{"=".repeat(40)}</div>
      <div className="flex justify-between">
        <span>Subtotal</span>
        <span>₹ {data.subtotal.toFixed(2)}</span>
      </div>
      <div className="flex justify-between">
        <span>SGST (2.5%)</span>
        <span>₹ {data.sgst.toFixed(2)}</span>
      </div>
      <div className="flex justify-between">
        <span>CGST (2.5%)</span>
        <span>₹ {data.cgst.toFixed(2)}</span>
      </div>
      <div className="flex justify-between font-bold">
        <span>Total</span>
        <span>₹ {Math.round(data.grand_total).toFixed(2)}</span>
      </div>
      <div className="text-center mt-2 text-xs">Thank you! Visit again</div>
    </div>
  );
}

function SettingsEditor({ settings, onChange }) {
  const [form, setForm] = useState(settings || {});
  useEffect(() => setForm(settings || {}), [settings]);

  const save = async () => {
    try {
      const res = await axios.put(`${API}/settings`, form);
      onChange && onChange(res.data);
      toast.success("Settings saved");
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Failed to save settings");
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Save size={16} /> Receipt Settings
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-3">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Setting</TableHead>
              <TableHead>Value</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            <TableRow>
              <TableCell>Hotel Name</TableCell>
              <TableCell>
                <Input
                  value={form.hotel_name || ""}
                  onChange={(e) =>
                    setForm({ ...form, hotel_name: e.target.value })
                  }
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>Phone</TableCell>
              <TableCell>
                <Input
                  value={form.phone || ""}
                  onChange={(e) => setForm({ ...form, phone: e.target.value })}
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>GSTIN</TableCell>
              <TableCell>
                <Input
                  value={form.gstin || ""}
                  onChange={(e) => setForm({ ...form, gstin: e.target.value })}
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>Address</TableCell>
              <TableCell>
                <Textarea
                  rows={2}
                  value={form.address || ""}
                  onChange={(e) =>
                    setForm({ ...form, address: e.target.value })
                  }
                />
              </TableCell>
            </TableRow>
          </TableBody>
        </Table>
        <div className="flex justify-end">
          <Button onClick={save} className="gap-2">
            <Save size={14} /> Save
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

function AdminPanel({ mode }) {
  const [settings, setSettings] = useState(null);

  const loadSettings = async () => {
    try {
      const res = await axios.get(`${API}/settings`);
      setSettings(res.data);
    } catch {}
  };

  useEffect(() => {
    if (mode === "admin-full") {
      loadSettings();
    }
  }, [mode]);

  const isAdmin = mode.includes("admin");
  if (!isAdmin) return null;
  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle>Admin Actions ({mode})</CardTitle>
        </CardHeader>
        <CardContent>
          <ul className="list-disc ml-5">
            <li>Menu Management (Available)</li>
            <li>Bill Generation (Available)</li>
            <li>Settings Configuration (Available)</li>
            <li>Reporting (Coming Soon)</li>
            <li>Shift Management (Coming Soon)</li>
            <li>Audit Trail (Coming Soon)</li>
          </ul>
        </CardContent>
      </Card>
      {mode === "admin-full" && settings && (
        <SettingsEditor settings={settings} onChange={setSettings} />
      )}
    </div>
  );
}

function App() {
  const [mode, setMode] = useState("none");
  const [billingDate, setBillingDate] = useState(null);
  const [track, setTrack] = useState("");
  const [isVerifyingAdmin, setIsVerifyingAdmin] = useState(false);

  const isAdmin = mode.includes("admin");
  const [drafts, setDrafts] = useState({});
  const [currentTable, setCurrentTable] = useState("");
  const [activeTab, setActiveTab] = useState("billing");

  const handleLogin = (newMode, date, newTrack) => {
    setMode(newMode);
    setBillingDate(date);
    setTrack(newTrack);
    setIsVerifyingAdmin(false);
  };

  const handleStartAdminVerification = (date, newTrack) => {
    setBillingDate(date);
    setTrack(newTrack);
    setIsVerifyingAdmin(true);
  };

  const handleVerificationComplete = (adminMode) => {
    setMode(adminMode);
    setIsVerifyingAdmin(false);
    toast.success(`Logged in as ${adminMode}`);
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-amber-50 to-orange-50 text-gray-800">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-6">
          <h1 className="text-2xl font-semibold tracking-tight">
            Udupi Anand Bhavan — Billing System
          </h1>
        </div>
        {mode === "none" ? (
          isVerifyingAdmin ? (
            <AdminVerificationScreen
              onVerificationComplete={handleVerificationComplete}
            />
          ) : (
            <div className="max-w-3xl">
              <LoginPanel
                onLogin={handleLogin}
                onStartAdminVerification={handleStartAdminVerification}
              />
            </div>
          )
        ) : (
          <Tabs value={activeTab} onValueChange={setActiveTab}>
            <TabsList>
              <TabsTrigger value="billing" className="gap-1">
                <FileText size={14} /> Billing
              </TabsTrigger>
              <TabsTrigger value="menu" className="gap-1">
                <ChefHat size={14} /> Food Menu
              </TabsTrigger>
              <TabsTrigger value="recent" className="gap-1">
                <History size={14} /> Recent Bills
              </TabsTrigger>
              {isAdmin && (
                <TabsTrigger value="admin" className="gap-1">
                  <LockKeyhole size={14} /> Admin
                </TabsTrigger>
              )}
            </TabsList>
            <TabsContent value="billing" className="mt-4">
              <Billing
                drafts={drafts}
                setDrafts={setDrafts}
                currentTable={currentTable}
                setCurrentTable={setCurrentTable}
                billingDate={billingDate}
                activeTab={activeTab}
                track={track}
              />
            </TabsContent>
            <TabsContent value="menu" className="mt-4">
              <FoodMenu mode={mode} />
            </TabsContent>
            <TabsContent value="recent" className="mt-4">
              <RecentBills billingDate={billingDate} />
            </TabsContent>
            {isAdmin && (
              <TabsContent value="admin" className="mt-4">
                <AdminPanel mode={mode} />
              </TabsContent>
            )}
          </Tabs>
        )}
      </div>
    </div>
  );
}

export default App;
